class Solution {
    public int countPairs(int[] nums, int low, int high) {
        int n = nums.length;
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (low <= (nums[i] ^ nums[j]) && (nums[i] ^ nums[j]) <= high) {
                    count++;
                }
            }
        }
        return count;
    }
}
